import{_ as s,o as e,c as i,a2 as t}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Vacuum, autovacuum y bloat","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/postgresql/14-vacuum-autovacuum-y-bloat.md","filePath":"bases-de-datos/postgresql/14-vacuum-autovacuum-y-bloat.md","lastUpdated":1782521464000}'),l={name:"bases-de-datos/postgresql/14-vacuum-autovacuum-y-bloat.md"};function n(o,a,u,c,r,p){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="vacuum-autovacuum-y-bloat" tabindex="-1">Vacuum, autovacuum y bloat <a class="header-anchor" href="#vacuum-autovacuum-y-bloat" aria-label="Permalink to &quot;Vacuum, autovacuum y bloat&quot;">​</a></h1><p>Por MVCC, PostgreSQL conserva versiones antiguas de filas. Vacuum limpia versiones que ya no son visibles para ninguna transaccion.</p><h2 id="por-que-existe-vacuum" tabindex="-1">Por que existe vacuum <a class="header-anchor" href="#por-que-existe-vacuum" aria-label="Permalink to &quot;Por que existe vacuum&quot;">​</a></h2><p>Un <code>UPDATE</code> crea una nueva version de fila. Un <code>DELETE</code> marca una version como no visible. Esas versiones antiguas ocupan espacio hasta que vacuum las procesa.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A[&quot;UPDATE frecuente&quot;] --&gt; B[&quot;versiones antiguas&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B --&gt; C[&quot;bloat&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C --&gt; D[&quot;VACUUM&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  D --&gt; E[&quot;espacio reutilizable&quot;]</span></span></code></pre></div><h2 id="vacuum" tabindex="-1">VACUUM <a class="header-anchor" href="#vacuum" aria-label="Permalink to &quot;VACUUM&quot;">​</a></h2><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VACUUM tabla;</span></span></code></pre></div><p><code>VACUUM</code> libera espacio para reutilizacion interna, pero no siempre devuelve espacio al sistema operativo.</p><h2 id="vacuum-full" tabindex="-1">VACUUM FULL <a class="header-anchor" href="#vacuum-full" aria-label="Permalink to &quot;VACUUM FULL&quot;">​</a></h2><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VACUUM FULL tabla;</span></span></code></pre></div><p>Reescribe la tabla y bloquea mas agresivamente. Debe usarse con cuidado.</p><h2 id="analyze" tabindex="-1">ANALYZE <a class="header-anchor" href="#analyze" aria-label="Permalink to &quot;ANALYZE&quot;">​</a></h2><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ANALYZE tabla;</span></span></code></pre></div><p>Actualiza estadisticas para que el planner estime mejor.</p><h2 id="autovacuum" tabindex="-1">Autovacuum <a class="header-anchor" href="#autovacuum" aria-label="Permalink to &quot;Autovacuum&quot;">​</a></h2><p>Autovacuum ejecuta vacuum y analyze automaticamente.</p><p>Senales de problemas:</p><ul><li>Tablas que crecen sin razon.</li><li>Muchas tuplas muertas.</li><li>Consultas cada vez mas lentas.</li><li>Logs de autovacuum frecuentes o fallidos.</li></ul><h2 id="transacciones-largas" tabindex="-1">Transacciones largas <a class="header-anchor" href="#transacciones-largas" aria-label="Permalink to &quot;Transacciones largas&quot;">​</a></h2><p>Una transaccion abierta durante mucho tiempo puede impedir limpiar versiones antiguas.</p><p>Consulta:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pid, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">state</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, xact_start, query</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pg_stat_activity</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> state</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;idle in transaction&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h2 id="bloat" tabindex="-1">Bloat <a class="header-anchor" href="#bloat" aria-label="Permalink to &quot;Bloat&quot;">​</a></h2><p>Bloat es espacio ocupado por versiones antiguas o paginas poco eficientes.</p><p>No todo crecimiento es bloat, pero updates/deletes intensivos lo pueden provocar.</p><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Manten transacciones cortas.</li><li>No desactives autovacuum salvo razon extrema.</li><li>Monitoriza tablas con muchos updates/deletes.</li><li>Ajusta autovacuum por tabla si hace falta.</li><li>Reindexa cuando indices tengan bloat significativo.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Ejecutar <code>VACUUM FULL</code> en produccion sin ventana.</li><li>Ignorar <code>idle in transaction</code>.</li><li>Pensar que vacuum reduce siempre el archivo en disco.</li><li>Desactivar autovacuum para &quot;mejorar rendimiento&quot;.</li><li>No actualizar estadisticas tras grandes cargas.</li></ul>`,29)])])}const m=s(l,[["render",n]]);export{h as __pageData,m as default};
